！[]&lt;a href=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/24.png?raw=true&#34;&gt;https://github.com/my011215/my011215.github.io/blob/main/image/24.png?raw=true&lt;/a&gt;)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/25.png?raw=true&#34; alt&gt;&lt;br&gt;
![]&lt;a href=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/26.png?raw=true&#34;&gt;https://github.com/my011215/my011215.github.io/blob/main/image/26.png?raw=true&lt;/a&gt;)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/27.png?raw=true&#34; alt&gt;&lt;br&gt;
